import React, { useState, useMemo } from 'react';
import { CalculatorDef, CalculatorCategory } from '../../types';
import { CALCULATORS } from '../../services/calculatorEngine';
import { 
  ChevronRight, 
  ChevronDown, 
  Search, 
  TrendingUp, 
  Activity, 
  Calculator as CalcIcon, 
  Cpu, 
  Settings, 
  X,
  Plus,
  Minus
} from 'lucide-react';
import * as LucideIcons from 'lucide-react';

const DynamicIcon = ({ name, size = 18 }: { name: string, size?: number }) => {
  const Icon = (LucideIcons as any)[name] || LucideIcons.Calculator;
  return <Icon size={size} />;
};

const CATEGORY_ICONS: Record<string, React.ReactNode> = {
  'Finance': <TrendingUp size={18} className="text-emerald-400" />,
  'Health': <Activity size={18} className="text-rose-400" />,
  'Math': <CalcIcon size={18} className="text-indigo-400" />,
  'Engineering': <Cpu size={18} className="text-amber-400" />,
  'Utility': <Settings size={18} className="text-slate-400" />,
};

interface MobileToolsProps {
  onSelectCalculator: (calc: CalculatorDef) => void;
}

export const MobileTools: React.FC<MobileToolsProps> = ({ onSelectCalculator }) => {
  const [searchQuery, setSearchQuery] = useState('');
  const [expandedCats, setExpandedCats] = useState<Set<string>>(new Set(['Finance', 'Math']));

  const groupedCalculators = useMemo(() => {
    const groups: Record<string, CalculatorDef[]> = {};
    const query = searchQuery.toLowerCase();

    CALCULATORS.forEach(calc => {
      if (
        query && 
        !calc.name.toLowerCase().includes(query) && 
        !calc.description.toLowerCase().includes(query)
      ) return;

      if (!groups[calc.category]) groups[calc.category] = [];
      groups[calc.category].push(calc);
    });
    return groups;
  }, [searchQuery]);

  const toggleCategory = (cat: string) => {
    const next = new Set(expandedCats);
    if (next.has(cat)) next.delete(cat);
    else next.add(cat);
    setExpandedCats(next);
  };

  const categories = Object.keys(groupedCalculators).sort();

  return (
    <div className="animate-fade-in flex flex-col h-full bg-slate-950">
      {/* Search Header */}
      <div className="sticky top-0 bg-slate-950/80 backdrop-blur-xl z-30 px-6 py-4 border-b border-white/5">
        <div className="relative group">
          <Search size={16} className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500 group-focus-within:text-indigo-400 transition-colors" />
          <input 
            type="text"
            placeholder="Search toolkits..."
            className="w-full bg-white/5 border border-white/10 rounded-2xl py-3.5 pl-11 pr-4 text-sm font-medium text-white placeholder:text-slate-600 focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500/40 transition-all"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
          {searchQuery && (
            <button 
              onClick={() => setSearchQuery('')}
              className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500 hover:text-white"
            >
              <X size={16} />
            </button>
          )}
        </div>
      </div>

      {/* Tree Content */}
      <div className="flex-1 overflow-y-auto no-scrollbar px-6 py-8 space-y-4 pb-32">
        {categories.length > 0 ? (
          categories.map(cat => {
            const isOpen = expandedCats.has(cat) || searchQuery !== '';
            const calcs = groupedCalculators[cat];

            return (
              <div key={cat} className="space-y-2">
                {/* Category Node */}
                <button
                  onClick={() => toggleCategory(cat)}
                  className={`w-full flex items-center justify-between p-4 rounded-2xl transition-all ${isOpen ? 'bg-white/5 border border-white/10' : 'bg-transparent border border-transparent'}`}
                >
                  <div className="flex items-center space-x-3">
                    <div className={`p-2 rounded-xl ${isOpen ? 'bg-slate-900' : 'bg-transparent border border-white/5'}`}>
                      {CATEGORY_ICONS[cat] || <CalcIcon size={18} />}
                    </div>
                    <div className="text-left">
                      <span className="text-[11px] font-black uppercase tracking-widest text-white">{cat}</span>
                      <p className="text-[9px] font-bold text-slate-500 uppercase tracking-tighter">{calcs.length} Tools</p>
                    </div>
                  </div>
                  <div className={`transition-transform duration-300 ${isOpen ? 'rotate-180' : ''}`}>
                    {isOpen ? <Minus size={16} className="text-indigo-500" /> : <Plus size={16} className="text-slate-600" />}
                  </div>
                </button>

                {/* Leaves (Calculators) */}
                {isOpen && (
                  <div className="grid grid-cols-1 gap-2 pl-4 border-l border-white/5 ml-6 py-2">
                    {calcs.map((calc, idx) => (
                      <button
                        key={calc.id}
                        onClick={() => onSelectCalculator(calc)}
                        className="flex items-center space-x-4 p-4 bg-white/[0.02] border border-white/5 rounded-2xl active:bg-indigo-500/10 active:border-indigo-500/20 transition-all text-left animate-fade-up"
                        style={{ animationDelay: `${idx * 0.05}s` }}
                      >
                        <div className="w-9 h-9 bg-slate-900 text-indigo-400 rounded-xl flex items-center justify-center shrink-0 shadow-inner">
                          <DynamicIcon name={calc.icon} size={16} />
                        </div>
                        <div className="flex-1 min-w-0">
                          <h4 className="text-xs font-bold text-slate-200 truncate">{calc.name}</h4>
                          <p className="text-[10px] text-slate-500 truncate mt-0.5 leading-tight">{calc.description}</p>
                        </div>
                        <div className="text-slate-700">
                          <ChevronRight size={14} />
                        </div>
                      </button>
                    ))}
                  </div>
                )}
              </div>
            );
          })
        ) : (
          <div className="py-20 text-center space-y-4">
            <div className="w-16 h-16 bg-slate-900 rounded-3xl flex items-center justify-center mx-auto text-slate-700">
               <Search size={32} />
            </div>
            <p className="text-sm font-bold text-slate-500">No matching toolkits found</p>
            <button 
              onClick={() => setSearchQuery('')}
              className="text-[10px] font-black uppercase tracking-widest text-indigo-500 px-4 py-2 bg-indigo-500/10 rounded-lg"
            >
              Clear Search
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

import React from 'react';
import { Home, Box, Search, Clock, Zap } from 'lucide-react';
import { MobileDashboard } from './MobileDashboard';
import { MobileTools } from './MobileTools';
import { MobileSearch } from './MobileSearch';
import { MobileHistory } from './MobileHistory';
import { MobileWorkspace } from './MobileWorkspace';
import { CalculatorDef, CalculatorCategory } from '../../types';

interface MobileViewProps {
  activeTab: 'home' | 'tools' | 'search' | 'history';
  onTabSelect: (tab: any) => void;
  selectedCalculator: CalculatorDef | null;
  onSelectCalculator: (calc: CalculatorDef | null) => void;
  activeCategory: CalculatorCategory | 'All';
  onSelectCategory: (cat: any) => void;
}

export const MobileView: React.FC<MobileViewProps> = ({
  activeTab,
  onTabSelect,
  selectedCalculator,
  onSelectCalculator,
  activeCategory,
  onSelectCategory
}) => {
  if (selectedCalculator) {
    return (
      <MobileWorkspace 
        calculator={selectedCalculator} 
        onBack={() => onSelectCalculator(null)} 
      />
    );
  }

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-slate-950">
      <header className="h-16 flex items-center justify-between px-6 shrink-0 z-30 bg-slate-950 border-b border-white/5">
        <div className="flex items-center space-x-2">
          <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white">
            <Zap size={18} />
          </div>
          <span className="text-lg font-black tracking-tighter uppercase text-white">OmniCalc</span>
        </div>
        <div className="w-9 h-9 rounded-full bg-slate-900 border border-slate-800 flex items-center justify-center">
          <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse" />
        </div>
      </header>

      <main className="flex-1 overflow-y-auto no-scrollbar">
        {activeTab === 'home' && <MobileDashboard onSelect={onSelectCalculator} />}
        {activeTab === 'tools' && (
          <MobileTools 
            onSelectCalculator={onSelectCalculator} 
          />
        )}
        {activeTab === 'search' && <MobileSearch onSelectCalculator={onSelectCalculator} />}
        {activeTab === 'history' && <MobileHistory />}
      </main>

      <nav className="fixed bottom-8 left-1/2 -translate-x-1/2 w-[92%] z-50">
        <div className="glass-heavy rounded-[2.5rem] p-2 ring-1 ring-white/10 flex justify-between shadow-2xl shadow-black/40">
          <TabButton icon={<Home size={22} />} label="Home" active={activeTab === 'home'} onClick={() => onTabSelect('home')} />
          <TabButton icon={<Box size={22} />} label="Tools" active={activeTab === 'tools'} onClick={() => onTabSelect('tools')} />
          <TabButton icon={<Search size={22} />} label="Search" active={activeTab === 'search'} onClick={() => onTabSelect('search')} />
          <TabButton icon={<Clock size={22} />} label="History" active={activeTab === 'history'} onClick={() => onTabSelect('history')} />
        </div>
      </nav>
    </div>
  );
};

const TabButton = ({ icon, label, active, onClick }: any) => (
  <button 
    onClick={onClick}
    className={`flex-1 flex flex-col items-center py-2.5 rounded-[2rem] transition-all relative ${active ? 'text-indigo-400 bg-white/5' : 'text-slate-500'}`}
  >
    {icon}
    <span className="text-[8px] font-black mt-1 uppercase tracking-tighter">{label}</span>
    {active && (
      <div className="absolute -bottom-1 w-1 h-1 bg-indigo-400 rounded-full" />
    )}
  </button>
);

export type CalculatorCategory = 'Finance' | 'Health' | 'Math' | 'Engineering' | 'Utility';

export type InputType = 'number' | 'slider' | 'currency' | 'select' | 'toggle' | 'date';

export interface ThemeSettings {
  mode: 'light' | 'dark' | 'midnight' | 'glass';
  accent: string;
  radius: 'none' | 'small' | 'medium' | 'large' | 'full';
  glassIntensity: 'none' | 'low' | 'medium' | 'high';
}

export interface SelectOption {
  label: string;
  value: string | number;
}

export interface CalculatorInput {
  id: string;
  label: string;
  type: InputType;
  defaultValue: number | string | boolean;
  min?: number;
  max?: number;
  step?: number;
  unit?: string;
  options?: SelectOption[]; // For select type
  description?: string;
  required?: boolean;
}

export interface CalculatorResult {
  id: string;
  label: string;
  value: number | string;
  type: 'currency' | 'percent' | 'number' | 'text' | 'duration';
  unit?: string;
  highlight?: boolean; // Primary result
}

export interface ChartDataPoint {
  name: string;
  value: number;
  fill?: string;
  [key: string]: any;
}

export interface ChartConfig {
  type: 'pie' | 'bar' | 'area' | 'composed';
  data: ChartDataPoint[];
  dataKeys?: string[]; // For multi-series
  colors?: string[];
  title?: string;
  xLabel?: string;
  yLabel?: string;
}

export interface CalculatorDef {
  id: string;
  name: string;
  description: string;
  category: CalculatorCategory;
  icon: string; // Lucide icon name
  inputs: CalculatorInput[];
  // function to compute raw key-value pairs
  calculate: (inputs: Record<string, any>) => Record<string, any>;
  // function to format raw values into displayable results
  formatResults: (raw: Record<string, any>) => CalculatorResult[];
  // function to generate chart data from raw values
  getChartData?: (raw: Record<string, any>) => ChartConfig | null;
}

export interface HistoryItem {
  id: string;
  calculatorId: string;
  calculatorName: string;
  timestamp: number;
  inputs: Record<string, any>;
  outputs: Record<string, any>; // Storing formatted values or raw
}

