import React, { useState, useEffect } from 'react';
import { MobileView } from './components/mobile/MobileView';
import { DesktopView } from './components/desktop/DesktopView';
import { CalculatorDef, CalculatorCategory, ThemeSettings } from './types';
import { SettingsOverlay } from './components/SettingsOverlay';

const DEFAULT_THEME: ThemeSettings = {
  mode: 'dark',
  accent: '#6366f1',
  radius: 'medium',
  glassIntensity: 'medium',
};

function App() {
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);
  const [activeCategory, setActiveCategory] = useState<CalculatorCategory | 'All'>('All');
  const [selectedCalculator, setSelectedCalculator] = useState<CalculatorDef | null>(null);
  const [mobileTab, setMobileTab] = useState<'home' | 'tools' | 'search' | 'history'>('home');

  // Theme State
  const [theme, setTheme] = useState<ThemeSettings>(() => {
    const saved = localStorage.getItem('omni-theme');
    return saved ? JSON.parse(saved) : DEFAULT_THEME;
  });
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  useEffect(() => {
    const handleResize = () => setIsMobile(window.innerWidth < 768);
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Sync Theme Settings to DOM
  useEffect(() => {
    const root = document.documentElement;
    localStorage.setItem('omni-theme', JSON.stringify(theme));

    // Accent Color Logic
    root.style.setProperty('--accent-color', theme.accent);
    // Rough way to get a dark version for hover states
    root.style.setProperty('--accent-color-dark', `${theme.accent}dd`);
    root.style.setProperty('--accent-glow', `${theme.accent}26`); // 15% opacity

    // Mode Logic
    root.classList.remove('dark', 'light');
    if (theme.mode === 'light') {
      root.classList.add('light');
      root.style.setProperty('--bg-primary', '#f8fafc');
      root.style.setProperty('--bg-secondary', '#ffffff');
      root.style.setProperty('--border-color', 'rgba(0, 0, 0, 0.08)');
      root.style.setProperty('--glass-bg', 'rgba(255, 255, 255, 0.7)');
    } else if (theme.mode === 'midnight') {
      root.classList.add('dark');
      root.style.setProperty('--bg-primary', '#000000');
      root.style.setProperty('--bg-secondary', '#0a0a0a');
      root.style.setProperty('--border-color', 'rgba(255, 255, 255, 0.12)');
      root.style.setProperty('--glass-bg', 'rgba(255, 255, 255, 0.02)');
    } else if (theme.mode === 'glass') {
      root.classList.add('dark');
      root.style.setProperty('--bg-primary', '#020617');
      root.style.setProperty('--bg-secondary', 'rgba(15, 23, 42, 0.4)');
      root.style.setProperty('--border-color', 'rgba(255, 255, 255, 0.1)');
      root.style.setProperty('--glass-bg', 'rgba(255, 255, 255, 0.05)');
    } else {
      root.classList.add('dark');
      root.style.setProperty('--bg-primary', '#020617');
      root.style.setProperty('--bg-secondary', '#0f172a');
      root.style.setProperty('--border-color', 'rgba(255, 255, 255, 0.08)');
      root.style.setProperty('--glass-bg', 'rgba(255, 255, 255, 0.03)');
    }

    // Radius Logic
    const radii = { none: '0', small: '0.5rem', medium: '1rem', large: '2rem', full: '9999px' };
    root.style.setProperty('--radius-xl', radii[theme.radius]);
    root.style.setProperty('--radius-2xl', `calc(${radii[theme.radius]} * 1.5)`);
    root.style.setProperty('--radius-3xl', `calc(${radii[theme.radius]} * 2)`);

    // Glass Intensity
    const intensities = { none: '0px', low: '8px', medium: '24px', high: '64px' };
    root.style.setProperty('--glass-blur', intensities[theme.glassIntensity]);
  }, [theme]);

  const handleCategorySelect = (cat: CalculatorCategory | 'All') => {
    setActiveCategory(cat);
    setSelectedCalculator(null);
  };

  const updateTheme = (newSettings: Partial<ThemeSettings>) => {
    setTheme(prev => ({ ...prev, ...newSettings }));
  };

  return (
    <>
      {isMobile ? (
        <MobileView 
          activeTab={mobileTab} 
          onTabSelect={setMobileTab}
          selectedCalculator={selectedCalculator}
          onSelectCalculator={setSelectedCalculator}
          activeCategory={activeCategory}
          onSelectCategory={handleCategorySelect}
          onOpenSettings={() => setIsSettingsOpen(true)}
        />
      ) : (
        <DesktopView 
          selectedCalculator={selectedCalculator}
          onSelectCalculator={setSelectedCalculator}
          activeCategory={activeCategory}
          onSelectCategory={handleCategorySelect}
          onOpenSettings={() => setIsSettingsOpen(true)}
        />
      )}

      <SettingsOverlay 
        isOpen={isSettingsOpen} 
        onClose={() => setIsSettingsOpen(false)} 
        settings={theme}
        onUpdate={updateTheme}
      />
    </>
  );
}

export default App;

