export const CIRCLE_CALCULATOR: CalculatorDef = {
  id: 'geometry-circle',
  name: 'Circle Geometry',
  description: 'Calculate area, circumference, and diameter from a radius or diameter input.',
  category: 'Math',
  icon: 'Circle',
  inputs: [
    { id: 'inputValue', label: 'Value', type: 'number', defaultValue: 5, unit: 'u' },
    { 
      id: 'inputType', 
      label: 'Input Type', 
      type: 'select', 
      defaultValue: 'radius', 
      options: [
        { label: 'Radius', value: 'radius' },
        { label: 'Diameter', value: 'diameter' }
      ] 
    },
  ],
  calculate: (inputs) => {
    const val = Number(inputs.inputValue);
    const r = inputs.inputType === 'radius' ? val : val / 2;
    const diameter = r * 2;
    const area = Math.PI * Math.pow(r, 2);
    const circumference = 2 * Math.PI * r;
    return { r, diameter, area, circumference };
  },
  formatResults: (raw) => [
    { id: 'area', label: 'Area', value: (raw.area as number).toFixed(4), type: 'number', unit: 'u²', highlight: true },
    { id: 'circ', label: 'Circumference', value: (raw.circumference as number).toFixed(4), type: 'number', unit: 'u' },
    { id: 'dia', label: 'Diameter', value: (raw.diameter as number).toFixed(4), type: 'number', unit: 'u' }
  ],
  getChartData: (raw) => ({
    type: 'pie',
    data: [
      { name: 'Radius', value: raw.r as number, fill: '#6366f1' },
      { name: 'Remaining Diameter', value: raw.r as number, fill: '#94a3b8' }
    ],
    title: 'Radius vs Diameter Ratio'
  })
};

import { CalculatorDef } from '../../types';

export const BASIC_STATS_CALCULATOR: CalculatorDef = {
  id: 'stats-basic',
  name: 'Descriptive Statistics',
  description: 'Calculate Mean, Median, Mode, and Standard Deviation for a dataset.',
  category: 'Math',
  icon: 'BarChart3',
  inputs: [
    { 
      id: 'dataset', 
      label: 'Dataset (Comma Separated)', 
      type: 'text', 
      defaultValue: '10, 20, 30, 40, 50', 
      description: 'Enter numbers separated by commas' 
    },
  ],
  calculate: (inputs) => {
    const nums = (inputs.dataset as string)
      .split(',')
      .map(n => parseFloat(n.trim()))
      .filter(n => !isNaN(n));

    if (nums.length === 0) return { error: 'Invalid data' };

    const sum = nums.reduce((a, b) => a + b, 0);
    const mean = sum / nums.length;

    const sorted = [...nums].sort((a, b) => a - b);
    const middle = Math.floor(sorted.length / 2);
    const median = sorted.length % 2 !== 0 
      ? sorted[middle] 
      : (sorted[middle - 1] + sorted[middle]) / 2;

    const variance = nums.reduce((a, b) => a + Math.pow(b - mean, 2), 0) / nums.length;
    const stdDev = Math.sqrt(variance);

    return { mean, median, stdDev, count: nums.length, min: Math.min(...nums), max: Math.max(...nums) };
  },
  formatResults: (raw) => {
    if (raw.error) return [{ id: 'err', label: 'Error', value: raw.error as string, type: 'text' }];
    return [
      { id: 'mean', label: 'Average (Mean)', value: (raw.mean as number).toFixed(2), type: 'number', highlight: true },
      { id: 'med', label: 'Median', value: (raw.median as number).toFixed(2), type: 'number' },
      { id: 'sd', label: 'Std. Deviation', value: (raw.stdDev as number).toFixed(2), type: 'number' },
      { id: 'range', label: 'Range', value: `${raw.min} - ${raw.max}`, type: 'text' }
    ];
  }
};

import { CalculatorDef } from '../../types';

export const LINEAR_EQUATION_CALCULATOR: CalculatorDef = {
  id: 'algebra-linear',
  name: 'Linear Solver',
  description: 'Find X or Y values for linear equations (y = mx + b).',
  category: 'Math',
  icon: 'GitCommit',
  inputs: [
    { id: 'm', label: 'Slope (m)', type: 'number', defaultValue: 2 },
    { id: 'b', label: 'Intercept (b)', type: 'number', defaultValue: 5 },
    { id: 'x', label: 'Value of X', type: 'number', defaultValue: 10 },
  ],
  calculate: (inputs) => {
    const m = Number(inputs.m);
    const b = Number(inputs.b);
    const x = Number(inputs.x);
    const y = (m * x) + b;
    return { y, m, b, x };
  },
  formatResults: (raw) => [
    { id: 'y', label: 'Result (Y)', value: raw.y as number, type: 'number', highlight: true },
    { id: 'eq', label: 'Equation', value: `y = ${raw.m}x + ${raw.b}`, type: 'text' }
  ],
  getChartData: (raw) => {
    const data = [];
    const m = raw.m as number;
    const b = raw.b as number;
    for (let i = -10; i <= 10; i += 2) {
      data.push({ name: i.toString(), value: (m * i) + b });
    }
    return {
      type: 'area',
      data: data,
      title: 'Linear Progression'
    };
  }
};

import { CalculatorDef } from '../types';
