import React, { useState, useEffect } from 'react';
import { MobileView } from './components/mobile/MobileView';
import { DesktopView } from './components/desktop/DesktopView';
import { CalculatorDef, CalculatorCategory, ThemeSettings } from './types';
import { SettingsOverlay } from './components/SettingsOverlay';
import { getCalculator } from './services/calculatorEngine';

const DEFAULT_THEME: ThemeSettings = {
  mode: 'dark',
  accent: '#6366f1',
  radius: 'medium',
  glassIntensity: 'medium',
};

function App() {
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);
  const [activeCategory, setActiveCategory] = useState<CalculatorCategory | 'All'>('All');
  const [selectedCalculator, setSelectedCalculator] = useState<CalculatorDef | null>(null);
  const [mobileTab, setMobileTab] = useState<'home' | 'tools' | 'search' | 'history'>('home');

  // Theme State
  const [theme, setTheme] = useState<ThemeSettings>(() => {
    const saved = localStorage.getItem('omni-theme');
    return saved ? JSON.parse(saved) : DEFAULT_THEME;
  });
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  // URL Routing Sync (Supports 300+ virtual pages)
  useEffect(() => {
    const handleHashChange = () => {
      const hash = window.location.hash.replace('#/', '');
      if (hash) {
        const calc = getCalculator(hash);
        if (calc) {
          setSelectedCalculator(calc);
          return;
        }
      }
      setSelectedCalculator(null);
    };

    window.addEventListener('hashchange', handleHashChange);
    handleHashChange(); // Initial load
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, []);

  useEffect(() => {
    const handleResize = () => setIsMobile(window.innerWidth < 768);
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Sync Theme Settings to DOM
  useEffect(() => {
    const root = document.documentElement;
    localStorage.setItem('omni-theme', JSON.stringify(theme));

    root.style.setProperty('--accent-color', theme.accent);
    root.style.setProperty('--accent-color-dark', `${theme.accent}dd`);
    root.style.setProperty('--accent-glow', `${theme.accent}26`);

    root.classList.remove('dark', 'light');
    if (theme.mode === 'light') {
      root.classList.add('light');
      root.style.setProperty('--bg-primary', '#f8fafc');
      root.style.setProperty('--bg-secondary', '#ffffff');
      root.style.setProperty('--border-color', 'rgba(0, 0, 0, 0.08)');
      root.style.setProperty('--glass-bg', 'rgba(255, 255, 255, 0.7)');
    } else if (theme.mode === 'midnight') {
      root.classList.add('dark');
      root.style.setProperty('--bg-primary', '#000000');
      root.style.setProperty('--bg-secondary', '#0a0a0a');
      root.style.setProperty('--border-color', 'rgba(255, 255, 255, 0.12)');
      root.style.setProperty('--glass-bg', 'rgba(255, 255, 255, 0.02)');
    } else if (theme.mode === 'glass') {
      root.classList.add('dark');
      root.style.setProperty('--bg-primary', '#020617');
      root.style.setProperty('--bg-secondary', 'rgba(15, 23, 42, 0.4)');
      root.style.setProperty('--border-color', 'rgba(255, 255, 255, 0.1)');
      root.style.setProperty('--glass-bg', 'rgba(255, 255, 255, 0.05)');
    } else {
      root.classList.add('dark');
      root.style.setProperty('--bg-primary', '#020617');
      root.style.setProperty('--bg-secondary', '#0f172a');
      root.style.setProperty('--border-color', 'rgba(255, 255, 255, 0.08)');
      root.style.setProperty('--glass-bg', 'rgba(255, 255, 255, 0.03)');
    }

    const radii = { none: '0', small: '0.5rem', medium: '1rem', large: '2rem', full: '9999px' };
    root.style.setProperty('--radius-xl', radii[theme.radius]);
    root.style.setProperty('--radius-2xl', `calc(${radii[theme.radius]} * 1.5)`);
    root.style.setProperty('--radius-3xl', `calc(${radii[theme.radius]} * 2)`);

    const intensities = { none: '0px', low: '8px', medium: '24px', high: '64px' };
    root.style.setProperty('--glass-blur', intensities[theme.glassIntensity]);
  }, [theme]);

  const handleCalculatorSelect = (calc: CalculatorDef | null) => {
    if (calc) {
      window.location.hash = `#/${calc.id}`;
    } else {
      window.location.hash = '';
    }
    setSelectedCalculator(calc);
  };

  const handleCategorySelect = (cat: CalculatorCategory | 'All') => {
    setActiveCategory(cat);
    handleCalculatorSelect(null);
  };

  const updateTheme = (newSettings: Partial<ThemeSettings>) => {
    setTheme(prev => ({ ...prev, ...newSettings }));
  };

  return (
    <>
      {isMobile ? (
        <MobileView 
          activeTab={mobileTab} 
          onTabSelect={setMobileTab}
          selectedCalculator={selectedCalculator}
          onSelectCalculator={handleCalculatorSelect}
          activeCategory={activeCategory}
          onSelectCategory={handleCategorySelect}
          onOpenSettings={() => setIsSettingsOpen(true)}
        />
      ) : (
        <DesktopView 
          selectedCalculator={selectedCalculator}
          onSelectCalculator={handleCalculatorSelect}
          activeCategory={activeCategory}
          onSelectCategory={handleCategorySelect}
          onOpenSettings={() => setIsSettingsOpen(true)}
        />
      )}

      <SettingsOverlay 
        isOpen={isSettingsOpen} 
        onClose={() => setIsSettingsOpen(false)} 
        settings={theme}
        onUpdate={updateTheme}
      />
    </>
  );
}

export default App;

export type CalculatorCategory = 'Finance' | 'Health' | 'Math' | 'Engineering' | 'Utility';

// Added 'text' to the InputType union to resolve type errors in calculators requiring string inputs
export type InputType = 'number' | 'slider' | 'currency' | 'select' | 'toggle' | 'date' | 'text';

export interface ThemeSettings {
  mode: 'light' | 'dark' | 'midnight' | 'glass';
  accent: string;
  radius: 'none' | 'small' | 'medium' | 'large' | 'full';
  glassIntensity: 'none' | 'low' | 'medium' | 'high';
}

export interface SelectOption {
  label: string;
  value: string | number;
}

export interface CalculatorInput {
  id: string;
  label: string;
  type: InputType;
  defaultValue: number | string | boolean;
  min?: number;
  max?: number;
  step?: number;
  unit?: string;
  options?: SelectOption[]; // For select type
  description?: string;
  required?: boolean;
}

export interface CalculatorResult {
  id: string;
  label: string;
  value: number | string;
  type: 'currency' | 'percent' | 'number' | 'text' | 'duration';
  unit?: string;
  highlight?: boolean; // Primary result
}

export interface ChartDataPoint {
  name: string;
  value: number;
  fill?: string;
  [key: string]: any;
}

export interface ChartConfig {
  type: 'pie' | 'bar' | 'area' | 'composed';
  data: ChartDataPoint[];
  dataKeys?: string[]; // For multi-series
  colors?: string[];
  title?: string;
  xLabel?: string;
  yLabel?: string;
}

export interface CalculatorDef {
  id: string;
  name: string;
  description: string;
  category: CalculatorCategory;
  icon: string; // Lucide icon name
  inputs: CalculatorInput[];
  // function to compute raw key-value pairs
  calculate: (inputs: Record<string, any>) => Record<string, any>;
  // function to format raw values into displayable results
  formatResults: (raw: Record<string, any>) => CalculatorResult[];
  // function to generate chart data from raw values
  getChartData?: (raw: Record<string, any>) => ChartConfig | null;
}

export interface HistoryItem {
  id: string;
  calculatorId: string;
  calculatorName: string;
  timestamp: number;
  inputs: Record<string, any>;
  outputs: Record<string, any>; // Storing formatted values or raw
}

import React from 'react';

export const CalculatorLogo: React.FC<{ className?: string }> = ({ className = "" }) => {
  return (
