                <button 
                  onClick={() => setTodos(todos.filter(t => t.id !== todo.id))}
                  className="text-slate-600 hover:text-rose-500 opacity-0 group-hover:opacity-100 transition-all"
                >
                  <Trash2 size={12} />
                </button>
              </div>
