        {/* 9. REMINDERS */}
        <div className="glass rounded-[2rem] p-6 flex flex-col justify-between space-y-4">
          <div className="flex items-center gap-2 text-rose-400">
            <Bell size={20} />
            <span className="text-[10px] font-black uppercase tracking-widest">Reminders</span>
          </div>
          <div className="space-y-2">
            <div className="p-3 bg-rose-500/5 border border-rose-500/10 rounded-xl">
              <p className="text-[10px] font-black text-rose-400 uppercase">12:00 PM</p>
              <p className="text-xs text-white font-bold truncate">Check Mortgage Rate</p>
            </div>
          </div>
