          <span className="text-xs font-black uppercase tracking-widest text-white">New Project</span>
        </button>
      </section>
    </div>
  );
};

import React from 'react';
import { CalculatorDef } from '../../types';
import { DashboardHome } from '../DashboardHome';

export const MobileDashboard: React.FC<{ onSelect: (c: CalculatorDef) => void }> = ({ onSelect }) => {
