          ))}
        </div>

        {/* Brand Stripe */}
        <div className="absolute bottom-0 left-0 w-full h-1 bg-accent/40"></div>

        {/* Reflection */}
        <div className="absolute top-0 left-0 w-[200%] h-full bg-gradient-to-tr from-white/10 to-transparent -rotate-45 -translate-x-full group-hover:translate-x-0 transition-transform duration-1000 pointer-events-none"></div>
      </div>

      {/* Floating Decorators (Only for large views) */}
      {(size === 'lg' || size === 'xl') && (
        <>
          <div className="absolute -top-6 -right-6 w-14 h-14 bg-rose-500 rounded-2xl border-4 border-slate-900 flex items-center justify-center text-white font-black text-xl shadow-xl animate-float rotate-12">
            %
          </div>
          <div className="absolute bottom-4 -left-8 w-12 h-12 bg-amber-400 rounded-full border-4 border-slate-900 flex items-center justify-center text-slate-900 font-black text-lg shadow-xl animate-float [animation-delay:1.5s] -rotate-12">
