import React, { useState, useEffect } from 'react';
import { 
  Clock, Calendar, Cloud, Timer, FileText, Bell, CheckSquare, 
  Zap, Battery, MapPin, Plus, Trash2, ChevronRight, Play, Pause, RotateCcw
} from 'lucide-react';
import { CalculatorLogo } from './CalculatorLogo';
import { CalculatorDef } from '../types';
import { CALCULATORS } from '../services/calculatorEngine';

interface DashboardHomeProps {
  onSelectCalculator: (calc: CalculatorDef) => void;
}

export const DashboardHome: React.FC<DashboardHomeProps> = ({ onSelectCalculator }) => {
  const [time, setTime] = useState(new Date());
  const [notepad, setNotepad] = useState(localStorage.getItem('omni-note') || '');
  const [todos, setTodos] = useState<{id: number, text: string, done: boolean}[]>(
    JSON.parse(localStorage.getItem('omni-todos') || '[]')
  );
  const [timer, setTimer] = useState(0);
  const [isTimerRunning, setIsTimerRunning] = useState(false);

  // Update Clock
  useEffect(() => {
    const timerId = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(timerId);
  }, []);

  // Save Notes/Todos
  useEffect(() => { localStorage.setItem('omni-note', notepad); }, [notepad]);
  useEffect(() => { localStorage.setItem('omni-todos', JSON.stringify(todos)); }, [todos]);

  // Timer Logic
  useEffect(() => {
    let interval: any;
    if (isTimerRunning) {
      interval = setInterval(() => setTimer(t => t + 1), 1000);
    }
    return () => clearInterval(interval);
  }, [isTimerRunning]);

  const formatTimer = (s: number) => {
    const mins = Math.floor(s / 60);
    const secs = s % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  const toggleTodo = (id: number) => {
    setTodos(todos.map(t => t.id === id ? { ...t, done: !t.done } : t));
  };

  return (
    <div className="max-w-7xl mx-auto p-6 md:p-10 space-y-16 animate-fade-in pb-40">
      {/* Hero Section */}
      <section className="grid grid-cols-1 lg:grid-cols-12 gap-12 items-center">
        <div className="lg:col-span-5 flex justify-center lg:justify-start">
          <CalculatorLogo size="xl" />
        </div>
        <div className="lg:col-span-7 space-y-8 text-center lg:text-left">
          <div className="inline-flex items-center space-x-2 bg-accent/10 border border-accent/20 px-4 py-2 rounded-full">
            <Zap size={14} className="text-accent animate-pulse" />
            <span className="text-[10px] font-black uppercase tracking-[0.2em] text-accent">Intelligent Computation Engine</span>
          </div>
          <h1 className="text-6xl md:text-8xl font-black tracking-tighter text-white leading-[0.85]">
            FUTURE <span className="text-accent">READY</span><br />
            CALCULUS.
          </h1>
          <p className="text-slate-400 text-xl font-medium max-w-2xl leading-relaxed">
            Experience the next generation of mathematical intelligence. Precision-engineered modules wrapped in a breathtaking fluid interface.
          </p>
          <div className="flex flex-wrap gap-5 justify-center lg:justify-start">
            <button 
              onClick={() => onSelectCalculator(CALCULATORS[0])}
              className="bg-accent hover:brightness-110 text-white px-10 py-5 rounded-[2rem] font-black uppercase tracking-[0.2em] shadow-2xl shadow-accent/30 flex items-center gap-3 transition-all active:scale-95"
            >
              Launch Core <Zap size={20} />
            </button>
            <button className="bg-white/5 hover:bg-white/10 text-white border border-white/10 px-10 py-5 rounded-[2rem] font-black uppercase tracking-[0.2em] transition-all">
              API Docs
            </button>
          </div>
        </div>
      </section>

      {/* Widgets Grid */}
      <section className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {/* 1. TIME */}
        <div className="glass rounded-[2.5rem] p-8 flex flex-col items-center justify-center space-y-3 border-b-8 border-accent">
          <Clock className="text-accent" size={28} />
          <div className="text-4xl font-black text-white mono tracking-tighter">
            {time.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
          </div>
          <span className="text-[10px] font-black uppercase tracking-[0.25em] text-slate-500">Atomic Clock</span>
        </div>

        {/* 2. DATE */}
        <div className="glass rounded-[2.5rem] p-8 flex flex-col items-center justify-center space-y-3 border-b-8 border-rose-500">
          <Calendar className="text-rose-500" size={28} />
          <div className="text-xl font-black text-white uppercase tracking-tight">
            {time.toLocaleDateString([], { weekday: 'short', month: 'short', day: 'numeric' })}
          </div>
          <span className="text-[10px] font-black uppercase tracking-[0.25em] text-slate-500">Gregorian Sync</span>
        </div>

        {/* 3. CLIMATE */}
        <div className="glass rounded-[2.5rem] p-8 flex flex-col items-center justify-center space-y-3 border-b-8 border-amber-500">
          <Cloud className="text-amber-500" size={28} />
          <div className="text-3xl font-black text-white mono tracking-tighter">24.5°C</div>
          <div className="flex items-center gap-2 text-[10px] font-black text-slate-500 uppercase tracking-widest">
            <MapPin size={10} className="text-amber-500" /> Cupertino, CA
          </div>
        </div>

        {/* 4. SYSTEM STATUS */}
        <div className="glass rounded-[2.5rem] p-8 flex flex-col items-center justify-center space-y-3 border-b-8 border-emerald-500">
          <Battery className="text-emerald-500" size={28} />
          <div className="text-3xl font-black text-white mono tracking-tighter">98%</div>
          <div className="w-full h-2 bg-slate-900 rounded-full overflow-hidden border border-white/5">
            <div className="w-[98%] h-full bg-emerald-500 shadow-[0_0_10px_rgba(16,185,129,0.5)]"></div>
          </div>
          <span className="text-[10px] font-black uppercase tracking-[0.25em] text-slate-500">Power Node</span>
        </div>

        {/* 5. TIMER (Wide) */}
        <div className="md:col-span-2 glass rounded-[3rem] p-10 flex items-center justify-between group overflow-hidden relative">
          <div className="absolute top-0 right-0 w-32 h-32 bg-accent/5 rounded-full blur-3xl -translate-y-12 translate-x-12"></div>
          <div className="space-y-2 relative z-10">
            <div className="flex items-center gap-3 text-accent">
              <Timer size={24} />
              <span className="text-[10px] font-black uppercase tracking-[0.3em]">Quantum Timer</span>
            </div>
            <div className="text-6xl font-black text-white mono tracking-tighter">
              {formatTimer(timer)}
            </div>
          </div>
          <div className="flex gap-3 relative z-10">
            <button 
              onClick={() => setIsTimerRunning(!isTimerRunning)}
              className="w-16 h-16 bg-accent rounded-3xl text-white shadow-xl shadow-accent/30 active:scale-90 transition-all flex items-center justify-center"
            >
              {isTimerRunning ? <Pause size={28} strokeWidth={2.5} /> : <Play size={28} strokeWidth={2.5} />}
            </button>
            <button 
              onClick={() => { setTimer(0); setIsTimerRunning(false); }}
              className="w-16 h-16 bg-slate-800 rounded-3xl text-slate-400 hover:text-white transition-all flex items-center justify-center border border-white/5"
            >
              <RotateCcw size={28} />
            </button>
          </div>
        </div>

        {/* 6. QUICK ACCESS (Wide) */}
        <div className="md:col-span-2 glass rounded-[3rem] p-10 space-y-8">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3 text-rose-500">
              <Zap size={24} />
              <span className="text-[10px] font-black uppercase tracking-[0.3em]">Synapse Shortcuts</span>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-4">
            {CALCULATORS.slice(0, 4).map(c => (
              <button 
                key={c.id}
                onClick={() => onSelectCalculator(c)}
                className="flex items-center justify-between p-4 bg-white/[0.03] border border-white/10 rounded-2xl hover:bg-accent/10 hover:border-accent/40 transition-all group"
              >
                <span className="text-xs font-black text-slate-200 truncate pr-2 uppercase tracking-tighter">{c.name}</span>
                <ChevronRight size={16} className="text-accent group-hover:translate-x-1 transition-transform" />
              </button>
            ))}
          </div>
        </div>

        {/* 7. NOTEPAD (Vertical) */}
        <div className="lg:row-span-2 glass rounded-[3rem] p-10 space-y-6 flex flex-col border-r-8 border-accent/20">
          <div className="flex items-center gap-3 text-accent">
            <FileText size={24} />
            <span className="text-[10px] font-black uppercase tracking-[0.3em]">Brain Dump</span>
          </div>
          <textarea 
            className="flex-1 bg-transparent border-none resize-none text-base font-medium text-slate-300 placeholder:text-slate-700 focus:ring-0 no-scrollbar leading-relaxed"
            placeholder="Initialize data capture..."
            value={notepad}
            onChange={(e) => setNotepad(e.target.value)}
          ></textarea>
          <div className="pt-6 border-t border-white/5 flex items-center justify-between">
            <span className="text-[9px] font-black text-slate-600 uppercase tracking-widest">Cache: 0.2MB</span>
            <div className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></div>
          </div>
        </div>

        {/* 8. TODO LIST */}
        <div className="md:col-span-2 lg:col-span-2 glass rounded-[3rem] p-10 space-y-8">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3 text-emerald-500">
              <CheckSquare size={24} />
              <span className="text-[10px] font-black uppercase tracking-[0.3em]">Neural Queue</span>
            </div>
            <button 
              onClick={() => {
                const text = prompt('Input neural command:');
                if (text) setTodos([{ id: Date.now(), text, done: false }, ...todos]);
              }}
              className="w-10 h-10 bg-emerald-500/10 text-emerald-500 rounded-xl hover:bg-emerald-500 hover:text-white transition-all flex items-center justify-center border border-emerald-500/20"
            >
              <Plus size={20} />
            </button>
          </div>
          <div className="space-y-4 max-h-[200px] overflow-y-auto no-scrollbar pr-2">
            {todos.length === 0 && (
              <div className="flex flex-col items-center justify-center py-10 space-y-2 opacity-30">
                <Zap size={40} />
                <p className="text-xs font-black uppercase tracking-widest">Queue Empty</p>
              </div>
            )}
            {todos.map(todo => (
              <div key={todo.id} className="flex items-center justify-between group bg-white/5 p-4 rounded-2xl border border-transparent hover:border-emerald-500/30 transition-all">
                <div 
                  className="flex items-center gap-4 cursor-pointer"
                  onClick={() => toggleTodo(todo.id)}
                >
                  <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-all ${todo.done ? 'bg-emerald-500 border-emerald-500' : 'border-white/20'}`}>
                    {todo.done && <Plus size={14} className="text-white rotate-45" />}
                  </div>
                  <span className={`text-sm font-bold tracking-tight ${todo.done ? 'text-slate-600 line-through' : 'text-slate-200'}`}>
                    {todo.text}
                  </span>
                </div>
                <button 
                  onClick={() => setTodos(todos.filter(t => t.id !== todo.id))}
                  className="text-slate-700 hover:text-rose-500 opacity-0 group-hover:opacity-100 transition-all"
                >
                  <Trash2 size={16} />
                </button>
              </div>
            ))}
          </div>
        </div>

        {/* 9. REMINDERS */}
        <div className="glass rounded-[2.5rem] p-8 flex flex-col justify-between space-y-6">
          <div className="flex items-center gap-3 text-rose-500">
            <Bell size={24} />
            <span className="text-[10px] font-black uppercase tracking-[0.3em]">Alerts</span>
          </div>
          <div className="space-y-3">
            <div className="p-4 bg-rose-500/5 border border-rose-500/10 rounded-2xl group hover:bg-rose-500/10 transition-all">
              <p className="text-[10px] font-black text-rose-500 uppercase tracking-widest mb-1">08:00 UTC</p>
              <p className="text-xs text-white font-bold leading-tight">Review Computational Log</p>
            </div>
          </div>
        </div>

        {/* 10. CALC SHORTCUT */}
