          onClick={() => onSelectCalculator(CALCULATORS[1])}
          className="bg-accent rounded-[2.5rem] p-8 flex flex-col items-center justify-center space-y-4 shadow-2xl shadow-accent/40 hover:scale-[1.02] active:scale-95 transition-all group overflow-hidden relative"
        >
          <div className="absolute inset-0 bg-white/10 opacity-0 group-hover:opacity-100 transition-opacity"></div>
          <div className="w-16 h-16 bg-white/20 rounded-full flex items-center justify-center text-white mb-2 relative z-10 border border-white/30 backdrop-blur-sm">
            <Plus size={32} strokeWidth={3} />
          </div>
          <span className="text-xs font-black uppercase tracking-[0.3em] text-white relative z-10">New Engine</span>
        </button>
      </section>
    </div>
  );
};

