export const CRYPTO_PROFIT_CALC: CalculatorDef = {
  id: 'finance-crypto-profit',
  name: 'Crypto Profit Tracker',
  description: 'Calculate ROI and net profit for your crypto trades including fees.',
  category: 'Finance',
  icon: 'Bitcoin',
  inputs: [
    { id: 'investment', label: 'Investment Amount', type: 'currency', defaultValue: 1000, unit: '$' },
    { id: 'buyPrice', label: 'Buy Price', type: 'number', defaultValue: 50000, unit: '$' },
    { id: 'sellPrice', label: 'Sell Price', type: 'number', defaultValue: 65000, unit: '$' },
    { id: 'fee', label: 'Exchange Fee', type: 'slider', defaultValue: 0.1, min: 0, max: 2, step: 0.01, unit: '%' },
  ],
  calculate: (inputs) => {
    const buy = Number(inputs.buyPrice);
    const sell = Number(inputs.sellPrice);
    const capital = Number(inputs.investment);
    const feePct = Number(inputs.fee) / 100;

    const coins = capital / buy;
    const grossSell = coins * sell;
    const totalFees = (capital * feePct) + (grossSell * feePct);
    const netProfit = grossSell - capital - totalFees;
    const roi = (netProfit / capital) * 100;

    return { netProfit, roi, totalFees, coins };
  },
  formatResults: (raw) => [
    { id: 'profit', label: 'Net Profit', value: raw.netProfit as number, type: 'currency', highlight: true },
    { id: 'roi', label: 'ROI', value: raw.roi as number, type: 'percent' },
    { id: 'coins', label: 'Asset Amount', value: (raw.coins as number).toFixed(6), type: 'number' }
  ]
};

