export const BODY_FAT_CALC: CalculatorDef = {
  id: 'health-body-fat',
  name: 'Body Fat Estimator',
  description: 'Estimate body fat percentage using the US Navy Method.',
  category: 'Health',
  icon: 'User',
  inputs: [
    { id: 'gender', label: 'Gender', type: 'select', defaultValue: 'male', options: [{label: 'Male', value: 'male'}, {label: 'Female', value: 'female'}] },
    { id: 'height', label: 'Height', type: 'number', defaultValue: 180, unit: 'cm' },
    { id: 'waist', label: 'Waist Circumference', type: 'number', defaultValue: 90, unit: 'cm' },
    { id: 'neck', label: 'Neck Circumference', type: 'number', defaultValue: 40, unit: 'cm' },
    { id: 'hip', label: 'Hip Circumference (Female Only)', type: 'number', defaultValue: 95, unit: 'cm' },
  ],
  calculate: (inputs) => {
    const h = Number(inputs.height);
    const w = Number(inputs.waist);
    const n = Number(inputs.neck);
    const hp = Number(inputs.hip);
    let fat = 0;

    if (inputs.gender === 'male') {
      fat = 495 / (1.0324 - 0.19077 * Math.log10(w - n) + 0.15456 * Math.log10(h)) - 450;
    } else {
      fat = 495 / (1.29579 - 0.35004 * Math.log10(w + hp - n) + 0.221 * Math.log10(h)) - 450;
    }
    return { fat: Math.max(0, fat) };
  },
  formatResults: (raw) => [
    { id: 'fat', label: 'Estimated Body Fat', value: raw.fat as number, type: 'percent', highlight: true }
  ]
};

