  icon: 'ArrowDownUp',
  inputs: [
    { id: 'force', label: 'Applied Force (F)', type: 'number', defaultValue: 1000, unit: 'N' },
    { id: 'area', label: 'Cross Section (A)', type: 'number', defaultValue: 50, unit: 'mm²' },
