import { SCENARIO_COMPARISON } from '../advanced_calculators/comparison/calc';
import { MONTE_CARLO_SIM } from '../advanced_calculators/simulations/monte_carlo';
import { API_BRIDGE } from '../advanced_calculators/api/connector';

const RAW_CALCULATORS: CalculatorDef[] = [
  ...LEGACY_FINANCE,
  LOAN_EMI_CALC,
  LUMPSUM_CALC,
  NPV_CALC,
  US_TAX_CALC,
  PAYROLL_CALC,
  CRYPTO_PROFIT_CALC,
  RETIREMENT_CALC,
  ...LEGACY_HEALTH,
  BMI_CALC,
  BODY_FAT_CALC,
  HEART_RATE_CALC,
  DOSAGE_CALC,
  PREGNANCY_CALC,
  SLEEP_CALC,
  ...LEGACY_ENGINEERING,
  PROJECTILE_MOTION_CALC,
  MOLARITY_CALC,
  RC_FILTER_CALC,
  CONCRETE_CALC,
  STRESS_STRAIN_CALC,
  ...LEGACY_UTILITY,
  AGE_CALCULATOR,
  TIMEZONE_CALCULATOR,
  UNIVERSAL_CONVERTER,
  CURRENCY_CONVERTER,
  PERCENTAGE_PRO,
  FORMULA_BUILDER,
  SYMBOLIC_MATH,
  SCENARIO_COMPARISON,
  MONTE_CARLO_SIM,
  API_BRIDGE,
  BASIC_ARITHMETIC,
  SCIENTIFIC_ADVANCED,
  TRIG_CALCULATOR,
  GRAPHING_CALC,
  CIRCLE_CALCULATOR,
  BASIC_STATS_CALCULATOR,
  LINEAR_EQUATION_CALCULATOR,
  MATRIX_CALCULATOR,
  COMPLEX_NUMBER_CALC,
  EQUATION_SYSTEM_SOLVER,
  PROBABILITY_CALC,
  NUMBER_THEORY_CALC,
  ...LEGACY_MATH
];

// Safety Wrapper: Ensures calculations don't throw errors that break the app
export const CALCULATORS = RAW_CALCULATORS.map(calc => ({
  ...calc,
  calculate: (inputs: Record<string, any>) => {
    try {
      const result = calc.calculate(inputs);
      // Deep sanitization of results
      Object.keys(result).forEach(key => {
        if (typeof result[key] === 'number' && !isFinite(result[key])) {
          result[key] = 'Error: Range exceeded';
        }
      });
      return result;
    } catch (e) {
      console.error(`Calculation failed for ${calc.id}:`, e);
      return { error: true, message: 'Computation failed' };
    }
  }
}));

export const getCalculator = (id: string) => CALCULATORS.find(c => c.id === id);

export const getCalculatorsByCategory = () => {
  const grouped: Record<string, CalculatorDef[]> = {};
  CALCULATORS.forEach(calc => {
    if (!grouped[calc.category]) grouped[calc.category] = [];
    grouped[calc.category].push(calc);
  });
  return grouped;
};

import { GoogleGenAI } from "@google/genai";

export const getAIExplanation = async (
  calculatorName: string,
  inputs: Record<string, any>,
  outputs: Record<string, any>
): Promise<string> => {
  if (!process.env.API_KEY) {
    return "AI insights are unavailable. API Key is missing from the environment.";
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Context: A professional user is using the "${calculatorName}" toolkit.
    Inputs: ${JSON.stringify(inputs, null, 2)}
    Calculated Results: ${JSON.stringify(outputs, null, 2)}

    Goal: Provide a high-level, strategic interpretation of these findings.
    - Explain the "Why" behind the "What".
    - If financial, discuss risks/opportunities. 
    - If health, discuss wellness implications.
    - If math/engineering, explain the physical/theoretical significance.
    - Formatting: Maximum 120 words. Use clear paragraphs. No markdown headers.
    - Tone: Sophisticated, architectural, precise.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.7,
        topP: 0.9,
        maxOutputTokens: 250,
      }
    });

    const text = response.text;
    return text || "Computation successful, but AI interpretation failed to converge. Please verify inputs.";
  } catch (error: any) {
    console.error("Gemini Critical Failure:", error);

    // Friendly error categorization
    if (error?.message?.includes('429')) return "High traffic. AI insights are currently throttled.";
    if (error?.message?.includes('400')) return "Input parameters are outside AI processing bounds.";

    return "The AI engine encountered a synchronization issue. Local math remains accurate.";
  }
};

import React from 'react';
import { CalculatorDef, CalculatorInput } from '../types';
import { TextField, SliderField } from './ui/Input';

interface CalculatorFormProps {
  calculator: CalculatorDef;
  values: Record<string, any>;
  onChange: (id: string, value: any) => void;
}

export const CalculatorForm: React.FC<CalculatorFormProps> = ({ calculator, values, onChange }) => {
  const renderInput = (input: CalculatorInput, index: number) => {
    const commonProps = {
      key: input.id,
      label: input.label,
      className: "animate-fade-up",
      style: { animationDelay: `${index * 0.05}s` }
    };

    switch (input.type) {
      case 'slider':
        return (
          <SliderField
            {...commonProps}
            min={input.min || 0}
            max={input.max || 100}
            step={input.step || 1}
            unit={input.unit}
            value={values[input.id] ?? input.defaultValue}
            onChange={(e) => onChange(input.id, Number(e.target.value))}
          />
        );
      case 'select':
        return (
          <div key={input.id} className={`flex flex-col space-y-2 ${commonProps.className}`} style={commonProps.style}>
            <label className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] ml-1">
              {input.label}
            </label>
            <select
              value={values[input.id] ?? input.defaultValue}
              onChange={(e) => onChange(input.id, e.target.value)}
              className="block w-full rounded-2xl border border-white/5 bg-slate-900/50 px-4 py-3.5 text-sm font-semibold text-white focus:outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500/50 transition-all hover:bg-slate-900"
            >
              {input.options?.map(opt => (
                <option key={opt.value} value={opt.value} className="bg-slate-900">{opt.label}</option>
              ))}
            </select>
          </div>
        );
      case 'date':
        return (
          <TextField
            {...commonProps}
            type="date"
            value={values[input.id] ?? input.defaultValue}
            onChange={(e) => onChange(input.id, e.target.value)}
          />
        );
      default:
        const isNumeric = input.type === 'number' || input.type === 'currency';
        return (
          <TextField
            {...commonProps}
            type={isNumeric ? 'number' : 'text'}
            unit={input.unit}
            value={values[input.id] ?? input.defaultValue}
            onChange={(e) => {
              const val = e.target.value;
              onChange(input.id, isNumeric ? (val === '' ? '' : Number(val)) : val);
            }}
            placeholder={input.description}
          />
        );
    }
  };

  return (
    <div className="space-y-8">
      <div className="grid grid-cols-1 gap-8">
        {calculator.inputs.map((input, idx) => renderInput(input, idx))}
      </div>
    </div>
  );
};

